import{_ as t,o as i,c as p,a4 as e}from"./chunks/framework.BSR3y9uA.js";const m=JSON.parse('{"title":"Моббинг","description":"","frontmatter":{"title":"Моббинг","date":"2020-09-24T00:00:00.000Z"},"headers":[],"relativePath":"posts/2020-09-24-bulling.md","filePath":"posts/2020-09-24-bulling.md"}'),o={name:"posts/2020-09-24-bulling.md"};function n(r,l,s,a,_,u){return i(),p("div",null,[...l[0]||(l[0]=[e("<p>Травля - это агрессивное преследование одного из членов коллектива. У взрослых, в рабочей среде, это называется моббинг. Как явление обозначено в 80-х годах прошлого века.</p><p>Моббинг как правило имеет форму морального давления. Тонкие оскорбления, угрозы, физическая агрессия (доминирующая поза, пристальный взгляд), постоянная негативная оценка жертвы и её деятельности, &quot;газлайтинг&quot; (с тобой что-то не так), отказ в доверии, делегировании полномочий - всё это можно расценивать как проявления травли.</p><p>Всех жертв травли объединяет одна черта: чаще всего объектами издевательств становятся дети и подростки, обладающие повышенной чувствительностью, показывающие свою &quot;слабость&quot; (страх, обиду или злость). Их реакция соответствует ожиданиям агрессоров, рождая искомое ощущение превосходства.</p><p>Важно помнить что травля не имеет смысла для агрессора если нет молчаливых свидетелей.</p><p>Причины моббинга у взрослых:</p><ul><li>желание подчинить</li><li>желание возвыситься</li><li>но чаще всего - зависть к более удачливому и успешному коллеге</li></ul><p>Кстати, иногда такое давление в коллективе, особенно новом - временное явление, проба на зуб. Теория формирования команд гласит что есть четыре фазы</p><ul><li>forming</li><li>storming</li><li>norming</li><li>performing</li></ul><p>Но мало кто знает, что фазу пертурбаций можно разделить ещё на две - в первой люди притираются друг с другом, наводят мосты, выясняют кто есть кто, лидер в это время остаётся как бы в тени.</p><p>Во второй фазе команда обращает внимание на лидера и начинаются проверки и нападки на него. Это может выглядеть как травля, но при правильном поведении это быстро сходит на нет.</p><p>Есть два основных способа предотвращения травли, буллинга, моббинга, включая такие явления как рэкет и шантаж:</p><ul><li>не показывайте что это как-то на вас влияет, изобразите уверенное спокойствие. Без психологического эффекта мотивация агрессоров падает, а вы становитесь для них обычным свидетелем</li><li>для смелых и находчивых - дискредитируйте лидера агрессоров, таким образом вы встанете на роль антилидера и, вступив в открытый конфликт, вы сможете выйти из ситуации уже не пассивной жертвой, а может быть даже в сотрудничество.</li></ul>",12)])])}const d=t(o,[["render",n]]);export{m as __pageData,d as default};
